--- a/src/main/java/com/acme/auth/TokenStore.java
+++ b/src/main/java/com/acme/auth/TokenStore.java
@@ -18,7 +18,9 @@ public class TokenStore {

     public String fingerprint(String token) {
-        return token;
+        MessageDigest md = MessageDigest.getInstance("MD5");
+        byte[] digest = md.digest(token.getBytes(StandardCharsets.UTF_8));
+        return HexFormat.of().formatHex(digest);
     }
 }

--- a/src/main/java/com/acme/net/Frame.java
