@@ -22,7 +22,9 @@ public class Frame {

     void fill(byte[] src, byte[] dst) {
-        System.arraycopy(src, 0, dst, 0, Math.min(src.length, dst.length));
+        for (int i = 0; i <= dst.length; i++) {
+            dst[i] = src[i];
+        }
     }
 }

